"""Rule-based typography checks using regex patterns."""

from __future__ import annotations

import re

from mcp_lektor.core.models import (
    ConfidenceLevel,
    CorrectionCategory,
    DocumentStructure,
    ProposedCorrection,
    TypographyRule,
)


def check_typography(
    structure: DocumentStructure,
    rules: list[TypographyRule],
) -> list[ProposedCorrection]:
    """Apply typography rules to all non-placeholder paragraphs.

    Each rule contains a regex *pattern* and a *replacement*.
    Returns a ProposedCorrection for every match.
    """
    corrections: list[ProposedCorrection] = []

    for para in structure.paragraphs:
        if para.is_placeholder_paragraph:
            continue

        for run_idx, run in enumerate(para.runs):
            if run.is_placeholder:
                continue
            text = run.text
            if not text.strip():
                continue

            for rule in rules:
                for match in re.finditer(rule.pattern, text):
                    replaced = re.sub(rule.pattern, rule.replacement, match.group(0))
                    category = _rule_category(rule)
                    corrections.append(
                        ProposedCorrection(
                            id="",
                            paragraph_index=para.index,
                            run_index=run_idx,
                            char_offset_start=match.start(),
                            char_offset_end=match.end(),
                            original_text=match.group(0),
                            suggested_text=replaced,
                            category=category,
                            confidence=ConfidenceLevel.HIGH,
                            explanation=rule.explanation,
                            rule_reference=rule.name,
                        )
                    )
    return corrections


def _rule_category(rule: TypographyRule) -> CorrectionCategory:
    """Map a rule's category string to the enum."""
    mapping = {
        "Typografie": CorrectionCategory.TYPOGRAPHY,
        "Anfuehrungszeichen": CorrectionCategory.QUOTATION_MARKS,
    }
    return mapping.get(rule.category, CorrectionCategory.TYPOGRAPHY)

"""Write accepted corrections back into the .docx with Track Changes."""

from __future__ import annotations

import json
import logging
from pathlib import Path
from typing import Any

from mcp_lektor.core.document_io import write_corrected_document

logger = logging.getLogger(__name__)

# Imported at module level so the server can register it
SESSION_STORE: dict[str, dict[str, Any]] = {}


async def write_corrected_docx(
    session_id: str,
    decisions: str = "",
    apply_all: bool = True,
    author: str = "MCP-Lektor",
) -> dict[str, Any]:
    """MCP tool: write corrections into the document as Track Changes.

    Args:
        session_id: The session identifier from extract_document.
        decisions: JSON string mapping correction index to
            "accept"/"reject"/"edit". Ignored if apply_all is True.
        apply_all: If True, apply all corrections regardless of decisions.
        author: Author name for Track Changes metadata.

    Returns:
        Dict with output_path, corrections_applied count, and status.
    """
    if session_id not in SESSION_STORE:
        return {
            "status": "error",
            "message": f"Session '{session_id}' not found. "
            "Please run extract_document first.",
        }

    session = SESSION_STORE[session_id]
    input_path = session.get("file_path")
    corrections = session.get("corrections", [])

    if not input_path or not Path(input_path).exists():
        return {
            "status": "error",
            "message": "Original document file not found in session.",
        }

    if not corrections:
        return {
            "status": "error",
            "message": "No corrections found. Please run proofread_text first.",
        }

    # Parse decisions
    decision_map: dict[int, str] | None = None
    if not apply_all and decisions:
        try:
            raw = json.loads(decisions)
            decision_map = {int(k): v for k, v in raw.items()}
        except (json.JSONDecodeError, ValueError) as exc:
            return {
                "status": "error",
                "message": f"Invalid decisions JSON: {exc}",
            }

    # Generate output path
    input_p = Path(input_path)
    output_path = input_p.parent / f"{input_p.stem}_corrected{input_p.suffix}"

    try:
        result_path = write_corrected_document(
            input_path=input_path,
            output_path=output_path,
            corrections=corrections,
            author=author,
            decisions=decision_map,
        )
    except Exception as exc:
        logger.exception("Failed to write corrected document")
        return {
            "status": "error",
            "message": f"Failed to write document: {exc}",
        }

    # Count applied
    if decision_map is not None:
        applied = sum(1 for v in decision_map.values() if v != "reject")
    else:
        applied = len(corrections)

    # Store output path in session
    session["output_path"] = str(result_path)

    return {
        "status": "success",
        "output_path": str(result_path),
        "corrections_applied": applied,
        "corrections_total": len(corrections),
        "message": (
            f"{applied} von {len(corrections)} Korrekturen wurden als "
            f"Track Changes in '{result_path.name}' geschrieben."
        ),
    }

"""Load YAML configuration files for proofreading rules."""

from __future__ import annotations

from pathlib import Path
from typing import Any

import yaml

from mcp_lektor.core.models import (
    ConfusedWordEntry,
    ProofreadingConfig,
    TypographyRule,
)

_CONFIG_DIR = Path(__file__).resolve().parent.parent.parent.parent / "config"


def load_config(config_dir: Path | None = None) -> ProofreadingConfig:
    """Load the main config.yaml and return a ProofreadingConfig."""
    base = config_dir or _CONFIG_DIR
    path = base / "config.yaml"
    if not path.exists():
        return ProofreadingConfig()
    with open(path, encoding="utf-8") as f:
        raw: dict[str, Any] = yaml.safe_load(f) or {}
    section = raw.get("proofreading", {})
    return ProofreadingConfig(**section)


def load_typography_rules(config_dir: Path | None = None) -> list[TypographyRule]:
    """Load typography_rules.yaml and return a list of TypographyRule."""
    base = config_dir or _CONFIG_DIR
    path = base / "typography_rules.yaml"
    if not path.exists():
        return []
    with open(path, encoding="utf-8") as f:
        raw = yaml.safe_load(f) or {}
    return [TypographyRule(**r) for r in raw.get("rules", [])]


def load_confused_words(config_dir: Path | None = None) -> list[ConfusedWordEntry]:
    """Load confused_words.yaml and return a list of ConfusedWordEntry."""
    base = config_dir or _CONFIG_DIR
    path = base / "confused_words.yaml"
    if not path.exists():
        return []
    with open(path, encoding="utf-8") as f:
        raw = yaml.safe_load(f) or {}
    return [ConfusedWordEntry(**w) for w in raw.get("words", [])]
